# Code generated by selo gen --lang python. DO NOT EDIT.

import json
import os

import pytest

from selo.cnh import (
    validate_cnh,
    format_cnh,
    generate_cnh,
)

_VECTOR_PATH = os.path.join(os.path.dirname(__file__), "..", "vectors", "cnh.json")
with open(_VECTOR_PATH, encoding="utf-8") as _f:
    VECTOR = json.load(_f)


@pytest.mark.parametrize("case", VECTOR["validate"])
def test_validate(case):
    assert validate_cnh(case["input"]) == case["valid"], f"validate {case['input']!r}"


@pytest.mark.parametrize("case", VECTOR["format"])
def test_format(case):
    if "error" in case:
        with pytest.raises(ValueError):
            format_cnh(case["input"])
    else:
        assert format_cnh(case["input"]) == case["output"], f"format {case['input']!r}"


def test_generate_round_trip():
    for _ in range(100):
        val = generate_cnh()
        assert validate_cnh(val), f"generate produced invalid: {val!r}"
